import rclpy
from rclpy.node import Node
from geometry_msgs.msg import PointStamped
from yolo_msg.msg import BoundingBoxArray  # 커스텀 메시지 패키지에 맞게 import

class SimpleSubscriber(Node):
    def __init__(self):
        super().__init__('simple_subscriber')

        # 필요한 토픽만 아래에서 주석 해제해서 사용하세요!

        # Yellow cone 중심점 (geometry_msgs/PointStamped)
        self.create_subscription(
            PointStamped,
            'yellow_cone',
            self.yellow_callback,
            10)
    # -----------------------------------------------------------
        # 예시: Yellow: (123.45, 67.89)
    # -----------------------------------------------------------

        # Blue cone 중심점 (geometry_msgs/PointStamped)

        self.create_subscription(
            PointStamped,
            'blue_cone',
            self.blue_callback,
            10)
    # -----------------------------------------------------------
        # 예시: Blue: (234.56, 78.90)
    # -----------------------------------------------------------

        # Pixel circle (geometry_msgs/PointStamped)

        self.create_subscription(
            PointStamped,
            'pixel_circle',
            self.pixel_callback,
            10)
    # -----------------------------------------------------------
        # 예시: PixelCircle: (345.67, 89.01)
    # -----------------------------------------------------------

        # Bounding box array (yolo_msg/BoundingBoxArray)

        self.create_subscription(
            BoundingBoxArray,
            'bounding_box',
            self.bbox_callback,
            10)

    # -----------------------------------------------------------
        # 예시:
        # BoundingBox count: 2
        # [0] class: yellow, conf: 0.98, box: (120, 60, 30, 40)
        # [1] class: blue, conf: 0.95, box: (220, 80, 28, 38)
    # -----------------------------------------------------------

    def yellow_callback(self, msg):
        self.get_logger().info(f'Yellow: ({msg.point.x:.2f}, {msg.point.y:.2f})')
        # 예시 출력: Yellow: (123.45, 67.89)

    def blue_callback(self, msg):
        self.get_logger().info(f'Blue: ({msg.point.x:.2f}, {msg.point.y:.2f})')
        # 예시 출력: Blue: (234.56, 78.90)

    def pixel_callback(self, msg):
        self.get_logger().info(f'PixelCircle: ({msg.point.x:.2f}, {msg.point.y:.2f})')
        # 예시 출력: PixelCircle: (345.67, 89.01)

    def bbox_callback(self, msg):
        self.get_logger().info(f'BoundingBox count: {len(msg.boxes)}')
        for i, box in enumerate(msg.boxes):
            self.get_logger().info(
                f'[{i}] class: {box.class_name}, conf: {box.confidence:.2f}, '
                f'box: ({box.x}, {box.y}, {box.width}, {box.height})'
            )
        # 예시 출력:
        # BoundingBox count: 2
        # [0] class: yellow, conf: 0.98, box: (120, 60, 30, 40)
        # [1] class: blue, conf: 0.95, box: (220, 80, 28, 38)

def main(args=None):
    rclpy.init(args=args)
    node = SimpleSubscriber()
    try:
        rclpy.spin(node)
    except KeyboardInterrupt:
        pass
    node.destroy_node()
    rclpy.shutdown()

if __name__ == '__main__':
    main()
